const __pageData = JSON.parse('{"title":"性能测试：负载与压力","description":"深入剖析性能测试的理论分类体系（负载/压力/soak/spike/容量测试）、Little定律与吞吐量-延迟权衡模型，并全面映射到JS/TS生态中的Lighthouse CI、k6、Artillery与性能预算CI enforcement工程实践。","frontmatter":{"title":"性能测试：负载与压力","description":"深入剖析性能测试的理论分类体系（负载/压力/soak/spike/容量测试）、Little定律与吞吐量-延迟权衡模型，并全面映射到JS/TS生态中的Lighthouse CI、k6、Artillery与性能预算CI enforcement工程实践。","date":"2026-05-01T00:00:00.000Z","tags":["测试工程","性能测试","Lighthouse","k6","负载测试","性能预算"],"category":"engineering"},"headers":[],"relativePath":"testing-engineering/10-performance-testing.md","filePath":"testing-engineering/10-performance-testing.md","lastUpdated":1777741461000}');
